# shapes.spy - Shape hierarchy with interfaces, abstract classes, and inheritance

interface IShape:
    def area(self) -> float: ...

interface IMeasurable:
    def perimeter(self) -> float: ...

@abstract
class Shape(IShape, IMeasurable):
    name: str

    def __init__(self, name: str):
        self.name = name

    @abstract
    def describe(self) -> str

@abstract
class Polygon(Shape):
    sides: int

    def __init__(self, name: str, sides: int):
        super().__init__(name)
        self.sides = sides

    @virtual
    def describe(self) -> str:
        return "Polygon: " + self.name

class Rectangle(Polygon):
    width: float
    height: float

    def __init__(self, width: float, height: float):
        super().__init__("Rectangle", 4)
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    @override
    def describe(self) -> str:
        return "Rectangle " + str(self.width) + "x" + str(self.height)

class Circle(Shape):
    radius: float

    def __init__(self, radius: float):
        super().__init__("Circle")
        self.radius = radius

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def perimeter(self) -> float:
        return 2.0 * 3.14159 * self.radius

    @override
    def describe(self) -> str:
        return "Circle with radius " + str(self.radius)

def create_rectangle(w: float, h: float) -> Rectangle:
    return Rectangle(w, h)

def create_circle(r: float) -> Circle:
    return Circle(r)

def total_area(shapes: list[IShape]) -> float:
    total: float = 0.0
    for s in shapes:
        total = total + s.area()
    return total

