# geometry_utils.spy - Utility types and functions for geometry operations

enum Color:
    RED = 1
    GREEN = 2
    BLUE = 3
    YELLOW = 4

enum LineStyle:
    SOLID = 0
    DASHED = 1
    DOTTED = 2

struct Point:
    x: float
    y: float

struct Dimension:
    width: float
    height: float

def midpoint(p1: Point, p2: Point) -> Point:
    return Point((p1.x + p2.x) / 2.0, (p1.y + p2.y) / 2.0)

def distance(p1: Point, p2: Point) -> float:
    dx: float = p2.x - p1.x
    dy: float = p2.y - p1.y
    return pow(dx * dx + dy * dy, 0.5)

def color_to_str(c: Color) -> str:
    if c == Color.RED:
        return "Red"
    elif c == Color.GREEN:
        return "Green"
    elif c == Color.BLUE:
        return "Blue"
    else:
        return "Yellow"

def scale_dimension(dim: Dimension, factor: float) -> Dimension:
    return Dimension(dim.width * factor, dim.height * factor)

class StyleConfig:
    color: Color
    line_style: LineStyle
    thickness: int

    def __init__(self, color: Color, style: LineStyle, thickness: int):
        self.color = color
        self.line_style = style
        self.thickness = thickness

    def get_summary(self) -> str:
        return color_to_str(self.color) + " " + str(self.thickness) + "px"

