# shape_collection.spy - Collection operations and shape management

from shapes import IShape
from geometry_utils import Color, StyleConfig

class ShapeEntry:
    shape: IShape
    color: Color
    id: int

    def __init__(self, shape: IShape, color: Color, id: int):
        self.shape = shape
        self.color = color
        self.id = id

class ShapeManager:
    entries: list[ShapeEntry]
    next_id: int

    def __init__(self):
        self.entries = []
        self.next_id = 1

    def add(self, shape: IShape, color: Color) -> int:
        entry: ShapeEntry = ShapeEntry(shape, color, self.next_id)
        self.entries.append(entry)
        current_id: int = self.next_id
        self.next_id = self.next_id + 1
        return current_id

    def get_areas(self) -> list[float]:
        areas: list[float] = []
        for entry in self.entries:
            areas.append(entry.shape.area())
        return areas

    def count(self) -> int:
        return len(self.entries)

    def describe_all(self) -> list[str]:
        descriptions: list[str] = []
        for entry in self.entries:
            descriptions.append(entry.shape.describe())
        return descriptions

def create_colored_entry(shape: IShape, color: Color, id: int) -> ShapeEntry:
    return ShapeEntry(shape, color, id)
